#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef int LL;
inline int read()
{
	int res(0);char ch(getchar());while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline void chkmin(T&x,const T&y){y<x?x=y:T();}
template<typename T> inline void chkmax(T&x,const T&y){x<y?x=y:T();}
const int N=5e5+10,INF=0x3f3f3f3f;int n,k;int t[1000010],a[N]; LL s[N],dp[N];int cnt[N];
inline LL w(const int &l,const int &r){int mid=(l+r)>>1;return ((mid<<1)-l-r)*a[mid]-s[mid]-s[mid-1]+s[l-1]+s[r];}
inline LL Cnt(const int &i,const int &j){return dp[j]+w(j+1,i);}
struct DP{int l,r,idx;inline DP(const int &x=0,const int &y=0,const int &i=0){l=y;r=i;idx=x;}}deq[N];int H,T;
inline bool jud(const int &l,const int &r1,const int &r2){LL v1=Cnt(l,r1),v2=Cnt(l,r2);return v1==v2?cnt[r1]<=cnt[r2]:v1<v2;}
inline bool check(const LL &x)
{
	dp[0]=cnt[0]=0;deq[H=T=1]=DP(0,1,n);rep(1,n,i)
	{
		while(deq[H].r==i-1)++H;int j=deq[H].idx;
		dp[i]=Cnt(i,j)-x;cnt[i]=cnt[j]+1;j=n+1;
		while(H<=T&&jud(deq[T].l,i,deq[T].idx))j=deq[T--].l;
		if(H>T){deq[++T]=DP(i,i+1,n);continue;}
		if(j<=n&&jud(deq[T].r,deq[T].idx,i)){deq[++T]=DP(i,j,n);continue;}
		LL l=deq[T].l,r=deq[T].r,mid=0;while(l<=r)jud(mid=(l+r)>>1,i,deq[T].idx)?r=mid-1,j=mid:l=mid+1;
		deq[T].r=j-1;deq[++T]=DP(i,j,n);
	}
	return cnt[n]<=k;
}
int main()
{
	n=read();k=read();rep(1,n,i)++t[read()];int tp=0;rep(0,10000,i)while(t[i]--)a[++tp]=i,s[tp]=s[tp-1]+i;
	LL l=-1e8,r=1e8,res=0,mid;while(l<=r)check(mid=(l+r)>>1)?l=mid+1,res=dp[n]+mid*k:r=mid-1;printf("%d\n",res);
}
